                    const a = ix + gridX1 * iz;
                    const b = ix + gridX1 * (iz + 1);
                    const c = (ix + 1) + gridX1 * (iz + 1);
                    const d = (ix + 1) + gridX1 * iz;
                    idx.push(a, b, d, b, c, d);
